import React, { forwardRef, useRef, useCallback, useEffect, useState } from 'react';
import { cn } from '@/utils/cn';
import styles from './Sidebar.module.css';

export type SidebarWidth = 'mini' | 'default' | number;

export interface SidebarProps {
  children: React.ReactNode;
  isCollapsed?: boolean;
  onToggle?: () => void;
  width?: SidebarWidth;
  onWidthChange?: (width: SidebarWidth) => void;
  resizable?: boolean;
  footer?: React.ReactNode;
  className?: string;
  isMobile?: boolean;
}

const MINI_WIDTH = 56;
const DEFAULT_WIDTH = 240;
const MIN_DRAG_WIDTH = 180;
const SNAP_THRESHOLD = 140;

export const Sidebar = forwardRef<HTMLElement, SidebarProps>(
  ({
    children,
    isCollapsed = false,
    onToggle,
    width = 'default',
    onWidthChange,
    resizable = true,
    footer,
    className,
    isMobile = false,
  }, ref) => {
    const internalRef = useRef<HTMLElement>(null);
    const sidebarRef = (ref as React.RefObject<HTMLElement>) || internalRef;
    const [isResizing, setIsResizing] = useState(false);

    const isMini = width === 'mini';
    const resolvedWidth = width === 'mini' ? MINI_WIDTH : width === 'default' ? DEFAULT_WIDTH : width;

    const handleMouseDown = useCallback((e: React.MouseEvent) => {
      if (!resizable || !onWidthChange) return;
      e.preventDefault();
      setIsResizing(true);
      const startX = e.clientX;

      const handleMouseMove = (e: MouseEvent) => {
        const newWidth = e.clientX;
        if (newWidth < SNAP_THRESHOLD) {
          onWidthChange('mini');
        } else if (newWidth < MIN_DRAG_WIDTH) {
          onWidthChange('default');
        } else {
          onWidthChange(newWidth);
        }
      };

      const handleMouseUp = () => {
        setIsResizing(false);
        document.removeEventListener('mousemove', handleMouseMove);
        document.removeEventListener('mouseup', handleMouseUp);
        document.body.style.cursor = '';
        document.body.style.userSelect = '';
      };

      document.body.style.cursor = 'col-resize';
      document.body.style.userSelect = 'none';
      document.addEventListener('mousemove', handleMouseMove);
      document.addEventListener('mouseup', handleMouseUp);
    }, [resizable, onWidthChange]);

    // Close sidebar on Escape (mobile)
    useEffect(() => {
      if (!isMobile || isCollapsed) return;
      const handleEscape = (e: KeyboardEvent) => {
        if (e.key === 'Escape') onToggle?.();
      };
      document.addEventListener('keydown', handleEscape);
      return () => document.removeEventListener('keydown', handleEscape);
    }, [isMobile, isCollapsed, onToggle]);

    if (isCollapsed && !isMobile) return null;

    return (
      <>
        {/* Mobile backdrop */}
        {isMobile && !isCollapsed && (
          <div className={styles.backdrop} onClick={onToggle} aria-hidden />
        )}
        <aside
          ref={sidebarRef}
          className={cn(
            styles.sidebar,
            isMini && styles.mini,
            isMobile && styles.mobile,
            isCollapsed && styles.collapsed,
            isResizing && styles.resizing,
            className
          )}
          style={{ width: isCollapsed ? 0 : resolvedWidth }}
          role="navigation"
          aria-label="Sidebar"
        >
          <div className={styles.content}>
            {children}
          </div>
          {footer && (
            <div className={styles.footer}>
              {footer}
            </div>
          )}
          {resizable && !isMobile && (
            <div
              className={styles.resizeHandle}
              onMouseDown={handleMouseDown}
              role="separator"
              aria-orientation="vertical"
              aria-label="Resize sidebar"
            />
          )}
        </aside>
      </>
    );
  }
);

Sidebar.displayName = 'Sidebar';

/* Sidebar */
.sidebar {
  display: flex;
  flex-direction: column;
  height: 100%;
  background-color: var(--color-background-secondary);
  border-right: var(--dimension-stroke-width-015) solid var(--color-border-primary);
  position: relative;
  flex-shrink: 0;
  overflow: hidden;
  transition: width var(--effect-motion-short-2);
}

.sidebar.resizing { transition: none; }

.sidebar.collapsed { width: 0 !important; border-right: none; }

.sidebar.mobile {
  position: fixed;
  top: 0;
  left: 0;
  bottom: 0;
  z-index: 9997;
}

.sidebar.mini .itemLabel { display: none; }
.sidebar.mini .itemBadge { display: none; }
.sidebar.mini .sectionHeader { display: none; }

.backdrop {
  position: fixed;
  inset: 0;
  background-color: var(--color-background-shade);
  z-index: 9996;
}

.content {
  flex: 1;
  overflow-y: auto;
  overflow-x: hidden;
  padding: var(--dimension-space-050);
  scrollbar-width: none;
}

.content::-webkit-scrollbar { display: none; }

.footer {
  flex-shrink: 0;
  padding: var(--dimension-space-050);
  border-top: var(--dimension-stroke-width-015) solid var(--color-border-primary);
}

/* Resize Handle */
.resizeHandle {
  position: absolute;
  top: 0;
  right: -3px;
  bottom: 0;
  width: 6px;
  cursor: col-resize;
  z-index: 10;
}

.resizeHandle:hover {
  background-color: var(--color-border-brand);
  opacity: 0.5;
}

/* Sections */
.section {
  display: flex;
  flex-direction: column;
}

.section + .section {
  margin-top: var(--dimension-space-050);
  padding-top: var(--dimension-space-050);
  border-top: var(--dimension-stroke-width-015) solid var(--color-border-primary);
}

.sectionHeader {
  padding: var(--dimension-space-050) var(--dimension-space-075);
  -webkit-user-select: none;
  user-select: none;
}

.sectionHeaderClickable { cursor: pointer; }

.sectionItems {
  display: flex;
  flex-direction: column;
  gap: var(--dimension-space-025);
}

/* Items */
.itemWrapper {
  display: flex;
  flex-direction: column;
}

.item {
  display: flex;
  align-items: center;
  gap: var(--dimension-space-075);
  padding: var(--dimension-space-075);
  background-color: transparent;
  border: none;
  border-radius: var(--dimension-radius-075);
  cursor: pointer;
  width: 100%;
  text-align: left;
  position: relative;
  min-height: var(--dimension-size-400);
  transition: background-color var(--effect-motion-short-2);
}

.item::before {
  content: '';
  position: absolute;
  inset: 0;
  background-color: transparent;
  border-radius: var(--dimension-radius-075);
  transition: var(--effect-transition-interaction-background-short-2);
  pointer-events: none;
}

.item:hover::before { background-color: var(--color-interaction-hover); }
.item:active::before { background-color: var(--color-interaction-pressed); }

.itemSelected { background-color: var(--color-background-faint-brand); }
.itemSelected::before { display: none; }

.itemDisabled { opacity: 0.5; cursor: not-allowed; pointer-events: none; }

.itemIcon {
  flex-shrink: 0;
  display: flex;
  align-items: center;
  color: var(--color-foreground-secondary);
}

.itemSelected .itemIcon { color: var(--color-foreground-primary); }

.itemLabel {
  flex: 1;
  min-width: 0;
}

.itemBadge {
  flex-shrink: 0;
  display: flex;
  align-items: center;
}

/* Sub-items */
.subItems {
  display: flex;
  flex-direction: column;
  padding-left: var(--dimension-space-300);
  gap: var(--dimension-space-025);
}

import React, { forwardRef } from 'react';
import { cn } from '@/utils/cn';
import { Text } from '@/components/Text';
import type { IconComponent } from '@/types';
import styles from './Sidebar.module.css';

export interface SidebarItemProps {
  label: string;
  icon?: IconComponent;
  isSelected?: boolean;
  isDisabled?: boolean;
  onClick?: () => void;
  badge?: React.ReactNode;
  children?: React.ReactNode;
  className?: string;
}

export const SidebarItem = forwardRef<HTMLButtonElement, SidebarItemProps>(
  ({ label, icon: Icon, isSelected = false, isDisabled = false, onClick, badge, children, className }, ref) => (
    <div className={cn(styles.itemWrapper, className)}>
      <button
        ref={ref}
        className={cn(
          styles.item,
          isSelected && styles.itemSelected,
          isDisabled && styles.itemDisabled
        )}
        onClick={onClick}
        disabled={isDisabled}
        type="button"
        aria-current={isSelected ? 'page' : undefined}
      >
        {Icon && (
          <span className={styles.itemIcon}>
            <Icon size={20} />
          </span>
        )}
        <Text
          variant={isSelected ? 'text-body-medium-emphasis' : 'text-body-medium'}
          as="span"
          className={styles.itemLabel}
          lineTruncation={1}
        >
          {label}
        </Text>
        {badge && <span className={styles.itemBadge}>{badge}</span>}
      </button>
      {children && isSelected && (
        <div className={styles.subItems}>
          {children}
        </div>
      )}
    </div>
  )
);

SidebarItem.displayName = 'SidebarItem';

import React, { forwardRef, useState } from 'react';
import { cn } from '@/utils/cn';
import { Text } from '@/components/Text';
import styles from './Sidebar.module.css';

export interface SidebarSectionProps {
  label?: string;
  children: React.ReactNode;
  collapsible?: boolean;
  defaultCollapsed?: boolean;
  className?: string;
}

export const SidebarSection = forwardRef<HTMLDivElement, SidebarSectionProps>(
  ({ label, children, collapsible = false, defaultCollapsed = false, className }, ref) => {
    const [isCollapsed, setIsCollapsed] = useState(defaultCollapsed);

    return (
      <div ref={ref} className={cn(styles.section, className)}>
        {label && (
          <div
            className={cn(styles.sectionHeader, collapsible && styles.sectionHeaderClickable)}
            onClick={collapsible ? () => setIsCollapsed(prev => !prev) : undefined}
            role={collapsible ? 'button' : undefined}
            aria-expanded={collapsible ? !isCollapsed : undefined}
          >
            <Text variant="text-caption-emphasis" as="span" color="tertiary">
              {label}
            </Text>
          </div>
        )}
        {!isCollapsed && (
          <div className={styles.sectionItems}>
            {children}
          </div>
        )}
      </div>
    );
  }
);

SidebarSection.displayName = 'SidebarSection';
